/// <summary>
/// Restricts the Journal Name lookup to only show 'DAILY' for entity y002
/// </summary>
[FormControlEventHandler(formControlStr(LedgerJournalTable, JournalName), FormControlEventType::Lookup)]
public static void JournalName_OnLookup(FormControl sender, FormControlEventArgs e)
{

    if (curExt() == 'y002')
    {

        FormControlCancelableSuperEventArgs cancelableArgs = e as FormControlCancelableSuperEventArgs;
        SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(LedgerJournalName), sender);
        sysTableLookup.addLookupfield(fieldNum(LedgerJournalName, JournalName));

        Query query = new Query();
        QueryBuildDataSource qbds = query.addDataSource(tableNum(LedgerJournalName));

        qbds.addRange(fieldNum(LedgerJournalName, JournalName)).value(queryValue('Daily'));


        sysTableLookup.parmQuery(query);


        sysTableLookup.performFormLookup();


        cancelableArgs.CancelSuperCall();
    }
}
